const config = $('Extract Contact Data').item.json;
const month = new Date().getMonth() + 1;
const bookingLink = (month >= 3 && month <= 8)
  ? config.BOOKING_LINK_INOFFICE
  : config.BOOKING_LINK_VIRTUAL;
const bookingType = (month >= 3 && month <= 8) ? 'in-office' : 'virtual';

return {
  json: {
    booking_link: bookingLink,
    booking_type: bookingType
  },
  binary: $input.item.binary
};

const data = $('Extract Contact Data').item.json;
const booking = $('Booking Link').item.json;

const nameParts = data.client_name.split(',');
const rawFirst = nameParts.length > 1 ? nameParts[1].trim() : data.client_name;
const firstName = rawFirst.charAt(0).toUpperCase() + rawFirst.slice(1).toLowerCase();

const accDate = new Date(data.date_of_accident);
const dateStr = accDate.toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric' });

const subject = 'Richards & Law - Your Case ' + data.case_id + ' - Next Steps';

const html = '<div style="font-family: Georgia, serif; max-width: 600px; margin: 0 auto; color: #333;">' +
  '<h2 style="color: #1a365d;">Richards & Law</h2>' +
  '<p>Dear ' + firstName + ',</p>' +
  '<p>Thank you for choosing Richards & Law to represent you in connection with the motor vehicle accident that occurred on ' + dateStr + ' at ' + data.accident_location + '.</p>' +
  '<p>We have prepared a retainer agreement for your review. Please find it attached to this email as a PDF document. We kindly ask that you review the agreement carefully and return a signed copy at your earliest convenience.</p>' +
  '<p>To discuss your case and next steps, we invite you to schedule a consultation with Attorney Andrew Richards:</p>' +
  '<p style="text-align: center;"><a href="' + booking.booking_link + '" style="display: inline-block; padding: 14px 28px; background-color: #1a365d; color: white; text-decoration: none; border-radius: 6px; font-weight: bold;">Schedule ' + booking.booking_type + ' consultation</a></p>' +
  '<p>If you have any questions in the meantime, please do not hesitate to contact our office.</p>' +
  '<p>Sincerely,<br><strong>Andrew Richards</strong><br>Attorney at Law<br>Richards & Law</p>' +
  '</div>';

// Fix double .pdf extension on retainer attachment
const binary = $input.item.binary;
if (binary && binary.retainer_pdf) {
  let fileName = binary.retainer_pdf.fileName || '';
  if (fileName.endsWith('.pdf.pdf')) {
    fileName = fileName.replace('.pdf.pdf', '.pdf');
  }
  binary.retainer_pdf.fileName = fileName;
}

return {
  json: {
    email_subject: subject,
    email_html: html,
    client_email: data.CLIENT_EMAIL_RECIPIENT,
    matter_id: data.matter_id,
    case_id: data.case_id,
    client_name: data.client_name,
    CLIO_API_BASE: data.CLIO_API_BASE
  },
  binary: binary
};

