const staticData = $getWorkflowStaticData('node');
const execId = $execution.id;

// Reset counter for new executions
if (staticData.currentExecId !== execId) {
  staticData.currentExecId = execId;
  staticData.retryCount = 0;
}

staticData.retryCount++;

if (staticData.retryCount > 8) {
  delete staticData.currentExecId;
  delete staticData.retryCount;
  throw new Error('Document automation timed out after 8 retries (120s). Check Clio document_automations status manually.');
}

return $input.item;
